import{_ as i,c as t,o as l,a1 as o,j as e,a as d,t as n}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Introdução: OpenCode Agent Skills | opencode-agent-skills","description":"Aprenda os valores e funcionalidades principais do OpenCode Agent Skills. Domine recursos como descoberta dinâmica de skills, injeção de contexto, compressão e recuperação, com compatibilidade Claude Code e recomendações automáticas.","frontmatter":{"title":"Introdução: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"Faça a IA Entender Suas Skills","subtitle":"Introdução: OpenCode Agent Skills","description":"Aprenda os valores e funcionalidades principais do OpenCode Agent Skills. Domine recursos como descoberta dinâmica de skills, injeção de contexto, compressão e recuperação, com compatibilidade Claude Code e recomendações automáticas.","tags":["Guia de Introdução","Introdução ao Plugin"],"prerequisite":[],"order":1},"headers":[],"relativePath":"pt/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"pt/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),r={name:"pt/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},c={tabindex:"0"};function u(s,a,p,m,g,h){return l(),t("div",null,[a[7]||(a[7]=o(`<h1 id="o-que-e-o-opencode-agent-skills" tabindex="-1">O que é o OpenCode Agent Skills? <a class="header-anchor" href="#o-que-e-o-opencode-agent-skills" aria-label="Permalink to &quot;O que é o OpenCode Agent Skills?&quot;">​</a></h1><h2 id="o-que-voce-aprendera" tabindex="-1">O Que Você Aprenderá <a class="header-anchor" href="#o-que-voce-aprendera" aria-label="Permalink to &quot;O Que Você Aprenderá&quot;">​</a></h2><ul><li>Entender os valores principais do plugin OpenCode Agent Skills</li><li>Dominar os principais recursos e funcionalidades do plugin</li><li>Compreender como as skills são descobertas e carregadas automaticamente</li><li>Distinguir este plugin de outras soluções de gerenciamento de skills</li></ul><h2 id="seus-desafios-atuais" tabindex="-1">Seus Desafios Atuais <a class="header-anchor" href="#seus-desafios-atuais" aria-label="Permalink to &quot;Seus Desafios Atuais&quot;">​</a></h2><p>Você pode ter encontrado estas situações:</p><ul><li><strong>Skills dispersas e difíceis de gerenciar</strong>: Skills espalhadas entre projetos, diretórios de usuário, cache de plugins e outros locais, tornando difícil encontrar a skill correta</li><li><strong>Problemas com sessões longas</strong>: Após sessões prolongadas, skills carregadas anteriormente se tornam inválidas devido à compressão de contexto</li><li><strong>Ansiedade de compatibilidade</strong>: Preocupação com a incompatibilidade de skills e plugins existentes após migrar do Claude Code</li><li><strong>Configuração repetitiva</strong>: Necessidade de reconfigurar skills para cada projeto, com falta de um mecanismo de gerenciamento unificado</li></ul><p>Estes problemas estão afetando sua eficiência no uso de assistentes de IA.</p><h2 id="conceito-central" tabindex="-1">Conceito Central <a class="header-anchor" href="#conceito-central" aria-label="Permalink to &quot;Conceito Central&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> é um sistema de plugins que fornece capacidade de descoberta e gerenciamento dinâmico de skills para o OpenCode.</p><div class="info custom-block"><p class="custom-block-title">O que é uma Skill?</p><p>Uma skill (habilidade) é um módulo reutilizável que contém instruções de fluxo de trabalho de IA. Geralmente é um diretório contendo um arquivo <code>SKILL.md</code> (descrevendo a funcionalidade e método de uso da skill), juntamente com arquivos auxiliares possíveis (documentação, scripts, etc.).</p></div><p><strong>Valor Principal</strong>: Através da padronização do formato de skills (SKILL.md), possibilita a reutilização de skills entre projetos e sessões.</p><h3 id="arquitetura-tecnica" tabindex="-1">Arquitetura Técnica <a class="header-anchor" href="#arquitetura-tecnica" aria-label="Permalink to &quot;Arquitetura Técnica&quot;">​</a></h3><p>O plugin é desenvolvido com TypeScript + Bun + Zod, fornecendo 4 ferramentas principais:</p><table tabindex="0"><thead><tr><th>Ferramenta</th><th>Função</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>Injeta o conteúdo do SKILL.md da skill no contexto da sessão</td></tr><tr><td><code>read_skill_file</code></td><td>Lê arquivos de suporte no diretório da skill (documentação, configurações, etc.)</td></tr><tr><td><code>run_skill_script</code></td><td>Executa scripts executáveis no contexto do diretório da skill</td></tr><tr><td><code>get_available_skills</code></td><td>Obtém a lista de skills disponíveis atualmente</td></tr></tbody></table><h2 id="principais-recursos-e-funcionalidades" tabindex="-1">Principais Recursos e Funcionalidades <a class="header-anchor" href="#principais-recursos-e-funcionalidades" aria-label="Permalink to &quot;Principais Recursos e Funcionalidades&quot;">​</a></h2><h3 id="_1-descoberta-dinamica-de-skills" tabindex="-1">1. Descoberta Dinâmica de Skills <a class="header-anchor" href="#_1-descoberta-dinamica-de-skills" aria-label="Permalink to &quot;1. Descoberta Dinâmica de Skills&quot;">​</a></h3><p>O plugin descobre skills automaticamente de múltiplos locais, ordenados por prioridade:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (nível de projeto - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (nível de projeto - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (nível de usuário - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (nível de usuário - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (cache de plugins)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (plugins instalados)</span></span></code></pre></div><p><strong>Regra</strong>: A primeira skill correspondente é aplicada, skills subsequentes com o mesmo nome são ignoradas.</p><blockquote><p>Por que este design?</p><p>Skills em nível de projeto têm prioridade sobre skills em nível de usuário, permitindo que você customize comportamentos específicos em projetos sem afetar a configuração global.</p></blockquote><h3 id="_2-injecao-de-contexto" tabindex="-1">2. Injeção de Contexto <a class="header-anchor" href="#_2-injecao-de-contexto" aria-label="Permalink to &quot;2. Injeção de Contexto&quot;">​</a></h3><p>Quando você chama <code>use_skill</code>, o conteúdo da skill é injetado no contexto da sessão em formato XML:</p><ul><li><code>noReply: true</code> - A IA não responderá à mensagem injetada</li><li><code>synthetic: true</code> - Marcada como mensagem gerada pelo sistema (não exibida na UI, não contada como entrada do usuário)</li></ul><p>Isso significa que o conteúdo da skill persiste no contexto da sessão; mesmo quando a sessão cresce e a compressão de contexto ocorre, a skill permanece disponível.</p><h3 id="_3-mecanismo-de-compressao-e-recuperacao" tabindex="-1">3. Mecanismo de Compressão e Recuperação <a class="header-anchor" href="#_3-mecanismo-de-compressao-e-recuperacao" aria-label="Permalink to &quot;3. Mecanismo de Compressão e Recuperação&quot;">​</a></h3><p>Quando o OpenCode executa compressão de contexto (operação comum em sessões longas), o plugin escuta o evento <code>session.compacted</code> e reinjeta automaticamente a lista de skills disponíveis.</p><p>Isso garante que a IA sempre saiba quais skills estão disponíveis durante sessões longas, sem perder o acesso às skills devido à compressão.</p><h3 id="_4-compatibilidade-com-claude-code" tabindex="-1">4. Compatibilidade com Claude Code <a class="header-anchor" href="#_4-compatibilidade-com-claude-code" aria-label="Permalink to &quot;4. Compatibilidade com Claude Code&quot;">​</a></h3><p>O plugin é totalmente compatível com o sistema de skills e plugins do Claude Code, suportando:</p><ul><li>Skills do Claude Code (<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>)</li><li>Cache de plugins do Claude (<code>~/.claude/plugins/cache/...</code>)</li><li>Marketplace de plugins do Claude (<code>~/.claude/plugins/marketplaces/...</code>)</li></ul><p>Isso significa que se você usava Claude Code anteriormente, pode continuar usando as skills e plugins existentes após migrar para o OpenCode.</p><h3 id="_5-recomendacao-automatica-de-skills" tabindex="-1">5. Recomendação Automática de Skills <a class="header-anchor" href="#_5-recomendacao-automatica-de-skills" aria-label="Permalink to &quot;5. Recomendação Automática de Skills&quot;">​</a></h3><p>O plugin monitora suas mensagens, usando detecção de similaridade semântica para verificar se está relacionada a alguma skill disponível:</p><ul><li>Calcula o vetor de embedding da mensagem</li><li>Calcula a similaridade do cosseno com as descrições de todas as skills</li><li>Quando a similaridade excede o limiar, injeta um prompt de avaliação sugerindo que a IA carregue a skill relacionada</li></ul><p>Este processo é completamente automático; você não precisa lembrar os nomes das skills ou solicitar explicitamente.</p><h3 id="_6-integracao-com-superpowers-opcional" tabindex="-1">6. Integração com Superpowers (Opcional) <a class="header-anchor" href="#_6-integracao-com-superpowers-opcional" aria-label="Permalink to &quot;6. Integração com Superpowers (Opcional)&quot;">​</a></h3><p>O plugin suporta o fluxo de trabalho Superpowers, habilitado através de variáveis de ambiente:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>Quando habilitado, o plugin detecta automaticamente a skill <code>using-superpowers</code> e injeta orientações completas do fluxo de trabalho na inicialização da sessão.</p><h2 id="comparacao-com-outras-solucoes" tabindex="-1">Comparação com Outras Soluções <a class="header-anchor" href="#comparacao-com-outras-solucoes" aria-label="Permalink to &quot;Comparação com Outras Soluções&quot;">​</a></h2>`,40)),e("table",c,[a[6]||(a[6]=e("thead",null,[e("tr",null,[e("th",null,"Solução"),e("th",null,"Características"),e("th",null,"Cenário de Uso")])],-1)),e("tbody",null,[a[3]||(a[3]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"Descoberta dinâmica, recuperação de compressão, recomendação automática"),e("td",null,"Cenários que necessitam gerenciamento unificado e recomendação automática")],-1)),e("tr",null,[a[1]||(a[1]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[a[0]||(a[0]=d("Registro automático como ferramenta ",-1)),e("code",null,"skills_"+n(s.name),1)]),a[2]||(a[2]=e("td",null,"Cenários que necessitam chamada independente de ferramentas",-1))]),a[4]||(a[4]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"Fluxo de trabalho completo de desenvolvimento de software"),e("td",null,"Projetos que necessitam fluxos de processo estritos")],-1)),a[5]||(a[5]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"Modo servidor MCP"),e("td",null,"Cenários que necessitam uso de skills em múltiplas ferramentas")],-1))])]),a[8]||(a[8]=o('<p><strong>Por que escolher este plugin:</strong></p><ul><li>✅ <strong>Configuração Zero</strong>: Descoberta e gerenciamento automático de skills</li><li>✅ <strong>Recomendação Inteligente</strong>: Recomendação automática de skills relevantes baseada em correspondência semântica</li><li>✅ <strong>Recuperação de Compressão</strong>: Estável e confiável em sessões longas</li><li>✅ <strong>Compatibilidade</strong>: Integração perfeita com o ecossistema Claude Code existente</li></ul><h2 id="resumo-da-aula" tabindex="-1">Resumo da Aula <a class="header-anchor" href="#resumo-da-aula" aria-label="Permalink to &quot;Resumo da Aula&quot;">​</a></h2><p>O plugin OpenCode Agent Skills fornece capacidades completas de gerenciamento de skills para o OpenCode através de mecanismos de descoberta dinâmica, injeção de contexto e recuperação de compressão. Seus valores principais são:</p><ul><li><strong>Automatização</strong>: Reduz a carga de configuração manual e memorização de nomes de skills</li><li><strong>Estabilidade</strong>: Skills sempre disponíveis durante sessões longas</li><li><strong>Compatibilidade</strong>: Integração perfeita com o ecossistema Claude Code existente</li></ul><h2 id="proxima-aula" tabindex="-1">Próxima Aula <a class="header-anchor" href="#proxima-aula" aria-label="Permalink to &quot;Próxima Aula&quot;">​</a></h2><blockquote><p>Na próxima aula aprenderemos <strong><a href="./../installation/">Instalar OpenCode Agent Skills</a></strong>.</p><p>Você vai aprender:</p><ul><li>Como adicionar o plugin na configuração do OpenCode</li><li>Como verificar se o plugin foi instalado corretamente</li><li>Método de configuração para modo de desenvolvimento local</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Entrada do plugin e visão geral</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>Lista de recursos principais</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>Prioridade de descoberta de skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>Injeção de mensagem sintética</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Mecanismo de recuperação de compressão</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>Módulo de correspondência semântica</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>Constantes-chave</strong>:</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>: Modelo de embedding utilizado</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>: Limiar de similaridade semântica</li><li><code>TOP_K = 5</code>: Limite de número de skills retornado na recomendação automática</li></ul><p><strong>Funções-chave</strong>:</p><ul><li><code>discoverAllSkills()</code>: Descobre skills de múltiplas localizações</li><li><code>use_skill()</code>: Injeta o conteúdo da skill no contexto da sessão</li><li><code>matchSkills()</code>: Correspondência de skills relacionadas baseada em similaridade semântica</li><li><code>injectSyntheticContent()</code>: Injeta mensagem sintética na sessão</li></ul></details>',10))])}const f=i(r,[["render",u]]);export{b as __pageData,f as default};
